 44→    display: flex;
 45→    align-items: center;
 46→    justify-content: center;
 47→    background: #16213e;
 48→    color: #a0a0b0;
 49→    font-size: 0.85rem;
 50→    font-weight: 600;
 51→    height: 2rem;
 52→  }
 53→
 54→  .corner {
 55→    background: #16213e;
 56→  }
 57→
 58→  .square {
 59→    display: flex;
 60→    align-items: center;
 61→    justify-content: center;
 62→    font-size: clamp(1.5rem, 5vw, 3.2rem);
 63→    cursor: pointer;
 64→    user-select: none;
 65→    transition: background-color 0.15s;
 66→    aspect-ratio: 1;
 67→  }
 68→
 69→  .square.light { background: #e8dcc8; }
 70→  .square.dark  { background: #7b6b4f; }
 71→  .square:hover { filter: brightness(1.12); }
 72→
 73→  .square.selected { background: #f6e96b !important; }
 74→  .square.valid-move { position: relative; }
 75→  .square.valid-move::after {
 76→    content: '';
 77→    position: absolute;
 78→    width: 30%;
 79→    height: 30%;
 80→    background: rgba(0, 0, 0, 0.25);
 81→    border-radius: 50%;
 82→    pointer-events: none;
 83→  }
 84→  .square.valid-move.has-enemy::after {
 85→    width: 85%;
 86→    height: 85%;
 87→    background: transparent;
 88→    border: 5px solid rgba(0, 0, 0, 0.25);
 89→    border-radius: 50%;
 90→  }
 91→
 92→  .turn-indicator {
 93→    text-align: center;
 94→    color: #a0a0b0;
 95→    font-size: 1.1rem;
 96→    margin-top: 1rem;
 97→    font-weight: 600;
 98→  }
 99→</style>
100→</head>
101→<body>
102→
103→<div class="board-container" id="board"></div>
104→<div class="turn-indicator" id="turn">White's turn</div>
105→
106→<script>
107→const PIECES = {
108→  K: { type: 'king',   color: 'white', symbol: '\u2654' },
109→  Q: { type: 'queen',  color: 'white', symbol: '\u2655' },
110→  R: { type: 'rook',   color: 'white', symbol: '\u2656' },
111→  B: { type: 'bishop', color: 'white', symbol: '\u2657' },
112→  N: { type: 'knight', color: 'white', symbol: '\u2658' },
113→  P: { type: 'pawn',   color: 'white', symbol: '\u2659' },
114→  k: { type: 'king',   color: 'black', symbol: '\u265A' },
115→  q: { type: 'queen',  color: 'black', symbol: '\u265B' },
116→  r: { type: 'rook',   color: 'black', symbol: '\u265C' },
117→  b: { type: 'bishop', color: 'black', symbol: '\u265D' },
118→  n: { type: 'knight', color: 'black', symbol: '\u265E' },
119→  p: { type: 'pawn',   color: 'black', symbol: '\u265F' },
120→};
121→
122→function makePiece(key) {
123→  if (!key) return null;
124→  const p = PIECES[key];
125→  return { type: p.type, color: p.color, symbol: p.symbol };
126→}
127→
128→// Board state: board[row][col], row 0 = rank 8 (top)
129→const INITIAL = [
130→  ['r','n','b','q','k','b','n','r'],
131→  ['p','p','p','p','p','p','p','p'],
132→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
133→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
134→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
135→  ['' ,'' ,'' ,'' ,'' ,'' ,'' ,''],
136→  ['P','P','P','P','P','P','P','P'],
137→  ['R','N','B','Q','K','B','N','R'],
138→];
139→
140→const boardState = INITIAL.map(row => row.map(makePiece));
141→
142→const FILES = ['a','b','c','d','e','f','g','h'];
143→const container = document.getElementById('board');
144→const turnIndicator = document.getElementById('turn');
145→
146→let currentTurn = 'white';
147→let selectedSquare = null; // { row, col }
148→let validMoves = [];       // [{ row, col }, ...]
149→
150→function inBounds(r, c) {
151→  return r >= 0 && r < 8 && c >= 0 && c < 8;
152→}
153→
154→function slidingMoves(row, col, directions) {
155→  const piece = boardState[row][col];
156→  const moves = [];
157→  for (const [dr, dc] of directions) {
158→    let r = row + dr, c = col + dc;
159→    while (inBounds(r, c)) {
160→      const target = boardState[r][c];
161→      if (!target) {
162→        moves.push({ row: r, col: c });
163→      } else {
164→        if (target.color !== piece.color) moves.push({ row: r, col: c });
165→        break;
166→      }
167→      r += dr;
168→      c += dc;
169→    }
170→  }
171→  return moves;
172→}
173→
174→function getValidMoves(piece, row, col) {
175→  const moves = [];
176→
177→  if (piece.type === 'pawn') {
178→    const dir = piece.color === 'white' ? -1 : 1;
179→    const startRow = piece.color === 'white' ? 6 : 1;
180→    // Forward one
181→    if (inBounds(row + dir, col) && !boardState[row + dir][col]) {
182→      moves.push({ row: row + dir, col });
183→      // Forward two from start
184→      if (row === startRow && !boardState[row + 2 * dir][col]) {
185→        moves.push({ row: row + 2 * dir, col });
186→      }
187→    }
188→    // Diagonal captures
189→    for (const dc of [-1, 1]) {
190→      const nr = row + dir, nc = col + dc;
191→      if (inBounds(nr, nc) && boardState[nr][nc] && boardState[nr][nc].color !== piece.color) {
192→        moves.push({ row: nr, col: nc });
193→      }
194→    }
195→  }
196→
197→  if (piece.type === 'rook' || piece.type === 'queen') {
198→    moves.push(...slidingMoves(row, col, [[1,0],[-1,0],[0,1],[0,-1]]));
199→  }
200→
201→  if (piece.type === 'bishop' || piece.type === 'queen') {
202→    moves.push(...slidingMoves(row, col, [[1,1],[1,-1],[-1,1],[-1,-1]]));
203→  }
204→
205→  if (piece.type === 'knight') {
206→    for (const [dr, dc] of [[2,1],[2,-1],[-2,1],[-2,-1],[1,2],[1,-2],[-1,2],[-1,-2]]) {
207→      const nr = row + dr, nc = col + dc;
208→      if (inBounds(nr, nc)) {
209→        const target = boardState[nr][nc];
210→        if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
211→      }
212→    }
213→  }
214→
215→  if (piece.type === 'king') {
216→    for (let dr = -1; dr <= 1; dr++) {
217→      for (let dc = -1; dc <= 1; dc++) {
218→        if (dr === 0 && dc === 0) continue;
219→        const nr = row + dr, nc = col + dc;
220→        if (inBounds(nr, nc)) {
221→          const target = boardState[nr][nc];
222→          if (!target || target.color !== piece.color) moves.push({ row: nr, col: nc });
223→        }
224→      }
225→    }
226→  }
227→
228→  return moves;
229→}
230→
231→function getSquareEl(row, col) {
232→  return container.querySelector(`.square[data-row="${row}"][data-col="${col}"]`);
233→}
234→
235→function clearHighlights() {
236→  container.querySelectorAll('.square.selected, .square.valid-move').forEach(sq => {
237→    sq.classList.remove('selected', 'valid-move', 'has-enemy');
238→  });
239→}
240→
241→function applyHighlights() {
242→  if (!selectedSquare) return;
243→  getSquareEl(selectedSquare.row, selectedSquare.col).classList.add('selected');
244→  for (const m of validMoves) {
245→    const el = getSquareEl(m.row, m.col);
246→    el.classList.add('valid-move');
247→    if (boardState[m.row][m.col]) el.classList.add('has-enemy');
248→  }
249→}
250→
251→function movePiece(fromRow, fromCol, toRow, toCol) {
252→  boardState[toRow][toCol] = boardState[fromRow][fromCol];
253→  boardState[fromRow][fromCol] = null;
254→
255→  // Update DOM
256→  const fromEl = getSquareEl(fromRow, fromCol);
257→  const toEl = getSquareEl(toRow, toCol);
258→  fromEl.textContent = '';
259→  toEl.textContent = boardState[toRow][toCol].symbol;
260→
261→  // Switch turn
262→  currentTurn = currentTurn === 'white' ? 'black' : 'white';
263→  turnIndicator.textContent = currentTurn === 'white' ? "White's turn" : "Black's turn";
264→}
265→
266→function handleClick(row, col) {
267→  const piece = boardState[row][col];
268→
269→  // If a piece is already selected
270→  if (selectedSquare) {
271→    // Check if clicking a valid move destination
272→    const isValid = validMoves.some(m => m.row === row && m.col === col);
273→    if (isValid) {
274→      clearHighlights();
275→      movePiece(selectedSquare.row, selectedSquare.col, row, col);
276→      selectedSquare = null;
277→      validMoves = [];
278→      return;
279→    }
280→
281→    // Deselect current piece
282→    const prevRow = selectedSquare.row;
283→    const prevCol = selectedSquare.col;
284→    clearHighlights();
285→    selectedSquare = null;
286→    validMoves = [];
287→
288→    // If clicked a different own piece, select it instead
289→    if (piece && piece.color === currentTurn && !(row === prevRow && col === prevCol)) {
290→      // fall through to selection below
291→    } else {
292→      return;
293→    }
294→  }
295→
296→  // Select a piece of the current player
297→  if (piece && piece.color === currentTurn) {
298→    const moves = getValidMoves(piece, row, col);
299→    if (moves.length > 0) {
300→      selectedSquare = { row, col };
301→      validMoves = moves;
302→      applyHighlights();
303→    }
304→  }
305→}
306→
307→// Build the board
308→for (let row = 0; row < 8; row++) {
309→  const rl = document.createElement('div');
310→  rl.className = 'rank-label';
311→  rl.textContent = 8 - row;
312→  container.appendChild(rl);
313→
314→  for (let col = 0; col < 8; col++) {
315→    const sq = document.createElement('div');
316→    const isLight = (row + col) % 2 === 0;
317→    sq.className = 'square ' + (isLight ? 'light' : 'dark');
318→    sq.dataset.row = row;
319→    sq.dataset.col = col;
320→
321→    const piece = boardState[row][col];
322→    if (piece) sq.textContent = piece.symbol;
323→
324→    sq.addEventListener('click', () => handleClick(row, col));
325→
326→    container.appendChild(sq);
327→  }
328→}
329→
330→// File labels row
331→const corner = document.createElement('div');
332→corner.className = 'corner';
333→container.appendChild(corner);
334→
335→for (const f of FILES) {
336→  const fl = document.createElement('div');
337→  fl.className = 'file-label';
338→  fl.textContent = f;
339→  container.appendChild(fl);
340→}
341→</script>
342→</body>
343→</html>
